import { Component, Input, Output, EventEmitter } from '@angular/core';

import { FormsModule } from '@angular/forms';
import { PersonalInfo, Link } from '../../models';

@Component({
  selector: 'app-personal-info-editor',
  standalone: true,
  imports: [FormsModule],
  templateUrl: './personal-info-editor.html',
})
export class PersonalInfoEditorComponent {
  @Input() personalInfo!: PersonalInfo;
  @Output() dataChange = new EventEmitter<void>();

  public currentLink: Link = { preview_name: '', url: '' };

  onAddLink() {
    this.personalInfo.links.push({ ...this.currentLink });
    this.currentLink = { preview_name: '', url: '' };
    this.triggerChange();
  }

  triggerChange() {
    this.dataChange.emit();
  }
}
