import { Component, inject, OnInit, effect } from '@angular/core';
import { FormsModule } from '@angular/forms';

import { DataService } from '../data.service';
import {
  Resume,
  SectionType,
  PersonalInfo,
  Experience,
  Education,
  Project,
  Achievement,
  Skill,
} from '../models';
import { TemplateSelectorComponent } from '../template-selector/template-selector.component';
import { PersonalInfoEditorComponent } from './personal-info-editor/personal-info-editor';
import { SkillsEditorComponent } from './skills-editor/skills-editor';
import { ExperienceEditorComponent } from './experience-editor/experience-editor';
import { ProjectsEditorComponent } from './projects-editor/projects-editor';
import { EducationEditorComponent } from './education-editor/education-editor';
import { AchievementsEditorComponent } from './achievements-editor/achievements-editor';
import { SummaryEditorComponent } from './summary-editor/summary-editor.component';

@Component({
  selector: 'app-editor',
  templateUrl: './editor.component.html',
  styleUrl: './editor.component.scss',
  imports: [
    FormsModule,
    TemplateSelectorComponent,
    PersonalInfoEditorComponent,
    SkillsEditorComponent,
    ExperienceEditorComponent,
    ProjectsEditorComponent,
    EducationEditorComponent,
    AchievementsEditorComponent,
    SummaryEditorComponent,
  ],
  standalone: true,
})
export class EditorComponent implements OnInit {
  private dataSerice = inject(DataService);
  private updateTimeout: any = null;
  private ignoreNextResumeSync = false;

  // Section display order (controls preview/PDF output order, not form order)
  sectionOrder: string[] = [
    'summary',
    'skills',
    'experience',
    'projects',
    'education',
    'achievements',
  ];

  // Display & Print Settings panel visibility
  showSettings = false;

  trackByIndex(index: number, item?: any): number {
    return index;
  }

  // Move a section TYPE up or down in the output order
  moveSectionType(index: number, direction: -1 | 1): void {
    const target = index + direction;
    if (target < 0 || target >= this.sectionOrder.length) return;
    [this.sectionOrder[index], this.sectionOrder[target]] = [
      this.sectionOrder[target],
      this.sectionOrder[index],
    ];
    this.debouncedSubmit();
  }

  // Use effect to automatically update the resume whenever any data changes
  constructor() {
    effect(() => {
      const activeResume = this.dataSerice.getResume()();
      if (!activeResume) return;

      if (this.ignoreNextResumeSync) {
        this.ignoreNextResumeSync = false;
        return;
      }
      this.loadResumeData(activeResume);
    });

    effect(() => {
      const trigger = this.dataSerice.getOpenSettingsTrigger()();
      if (trigger > 0) {
        this.showSettings = true;
        setTimeout(() => {
          document
            .getElementById('print-settings')
            ?.scrollIntoView({ behavior: 'smooth' });
        }, 100);
      }
    });
  }

  ngOnInit() {
    // If no active resume signal is set, we might need to rely on the current data
  }

  private loadResumeData(resume: Resume): void {
    // Clear existing data
    this.personalInfo = { name: '', email: '', phone: '', links: [] };
    this.skills = [];
    this.experiences = [];
    this.projects = [];
    this.educations = [];
    this.achievements = [];

    // Process each section from the resume
    resume.sections.forEach((section) => {
      switch (section.type) {
        case SectionType.PERSONAL_INFO:
          this.personalInfo = { ...(section.content as PersonalInfo) };
          break;
        case SectionType.SKILLS:
          this.skills.push({ ...(section.content as Skill) });
          break;
        case SectionType.EXPERIENCE:
          this.experiences.push({ ...(section.content as Experience) });
          break;
        case SectionType.PROJECTS:
          this.projects.push({ ...(section.content as Project) });
          break;
        case SectionType.EDUCATION:
          this.educations.push({ ...(section.content as Education) });
          break;
        case SectionType.ACHIEVEMENT:
          this.achievements.push({ ...(section.content as Achievement) });
          break;
      }
    });

    // Derive section type display order from the loaded resume's section sequence
    const typeKeyMap: Partial<Record<SectionType, string>> = {
      [SectionType.SUMMARY]: 'summary',
      [SectionType.SKILLS]: 'skills',
      [SectionType.EXPERIENCE]: 'experience',
      [SectionType.PROJECTS]: 'projects',
      [SectionType.EDUCATION]: 'education',
      [SectionType.ACHIEVEMENT]: 'achievements',
    };
    const seen = new Set<string>();
    const order: string[] = [];
    resume.sections.forEach((s) => {
      const key = typeKeyMap[s.type];
      if (key && !seen.has(key)) {
        seen.add(key);
        order.push(key);
      }
    });
    // Ensure all sections are present; summary always at top if not already in resume
    ['skills', 'experience', 'projects', 'education', 'achievements'].forEach(
      (k) => {
        if (!seen.has(k)) order.push(k);
      },
    );
    // Summary must always be present and at position 0 if the resume doesn't yet have it
    if (!seen.has('summary')) {
      order.unshift('summary');
    }
    this.sectionOrder = order;
  }

  debouncedSubmit() {
    if (this.updateTimeout) {
      clearTimeout(this.updateTimeout);
    }
    this.updateTimeout = setTimeout(() => {
      this.onSubmit();
      this.updateTimeout = null;
    }, 300);
  }

  public personalInfo: PersonalInfo = {
    name: '',
    email: '',
    phone: '',
    links: [],
  };
  public skills: Skill[] = [];
  public educations: Education[] = [];
  public experiences: Experience[] = [];
  public projects: Project[] = [];
  public achievements: Achievement[] = [];

  onSubmit() {
    const sectionMap: Record<string, any[]> = {
      skills: this.skills
        .filter(
          (skill) =>
            skill.skill_type ||
            (skill.skills?.length && skill.skills.some((s) => s.text)),
        )
        .map((skill) => ({ type: SectionType.SKILLS, content: skill })),
      experience: this.experiences
        .filter((exp) => exp.company || exp.position)
        .map((experience) => ({
          type: SectionType.EXPERIENCE,
          content: experience,
        })),
      projects: this.projects
        .filter((proj) => proj.project_name)
        .map((project) => ({ type: SectionType.PROJECTS, content: project })),
      education: this.educations
        .filter((edu) => edu.school || edu.degree)
        .map((education) => ({
          type: SectionType.EDUCATION,
          content: education,
        })),
      achievements: this.achievements
        .filter((ach) => ach.title)
        .map((achievement) => ({
          type: SectionType.ACHIEVEMENT,
          content: achievement,
        })),
    };

    // Preserve the Summary section — it is managed directly by SummaryEditorComponent
    // via DataService.setSummaryText(), not through the form binding here.
    // We read the current section object from the live resume to avoid wiping it.
    const currentResume = this.dataSerice.getResume()();
    const existingSummarySection = currentResume.sections.find(
      (s) => s.type === SectionType.SUMMARY,
    );

    const new_resume: Resume = {
      sections: [
        { type: SectionType.PERSONAL_INFO, content: this.personalInfo },
        ...this.sectionOrder.flatMap((key) => {
          if (key === 'summary') {
            // Re-insert the summary section at its ordered position if it exists
            return existingSummarySection ? [existingSummarySection] : [];
          }
          return sectionMap[key] || [];
        }),
      ],
    };

    this.ignoreNextResumeSync = true;
    this.dataSerice.updateResume(new_resume);
  }
}
