import {
  Component,
  inject,
  signal,
  HostListener,
  ViewChild,
  ElementRef,
} from '@angular/core';

import { FormsModule } from '@angular/forms';
import { DataService } from '../data.service';
import { ResumeProfile } from '../models';
import { NotificationService } from '../services/notification.service';

@Component({
  selector: 'app-profile-manager',
  standalone: true,
  imports: [FormsModule],
  styles: [
    `
      .dropdown-fixed {
        z-index: 1;
        position: fixed;
        max-width: 400px;
      }
    `,
  ],
  templateUrl: './profile-manager.component.html',
})
export class ProfileManagerComponent {
  private ds = inject(DataService);
  private ns = inject(NotificationService);

  @ViewChild('toggleBtn') toggleBtn!: ElementRef<HTMLButtonElement>;

  profiles = this.ds.getProfiles();
  activeProfileId = this.ds.getActiveProfileId();
  activeProfile = this.ds.getActiveProfile;

  isOpen = signal(false);
  creating = signal(false);
  newProfileName = '';
  renamingId = signal('');
  renameValue = '';

  // Computed position for the fixed dropdown
  dropdownTop = 0;
  dropdownLeft = 0;

  @HostListener('document:click')
  onDocumentClick() {
    this.isOpen.set(false);
  }

  toggleOpen() {
    const open = !this.isOpen();
    if (open && this.toggleBtn) {
      const rect = this.toggleBtn.nativeElement.getBoundingClientRect();
      this.dropdownTop = rect.bottom + 6;
      this.dropdownLeft = rect.left;
    }
    this.isOpen.set(open);
  }

  startCreate() {
    this.creating.set(true);
    this.newProfileName = '';
  }

  confirmCreate() {
    if (this.newProfileName.trim()) {
      const id = this.ds.createProfile(this.newProfileName);
      this.ds.switchProfile(id);
    }
    this.creating.set(false);
    this.isOpen.set(false);
  }

  switchProfile(id: string) {
    this.ds.switchProfile(id);
    this.isOpen.set(false);
  }

  startRename(profile: ResumeProfile) {
    this.renamingId.set(profile.id);
    this.renameValue = profile.name;
  }

  confirmRename(id: string) {
    if (this.renameValue.trim()) this.ds.renameProfile(id, this.renameValue);
    this.renamingId.set('');
  }

  async deleteProfile(id: string) {
    const name =
      this.profiles().find((p) => p.id === id)?.name ?? 'this profile';
    const ok = await this.ns.confirm(
      `Delete "${name}"? This cannot be undone.`,
      'Delete',
    );
    if (ok) this.ds.deleteProfile(id);
  }
}
