import { Component, inject, EventEmitter, Output } from '@angular/core';

import { DataService } from '../data.service';
import { NotificationService } from '../services/notification.service';

@Component({
  selector: 'app-resume-manager',
  standalone: true,
  imports: [],
  templateUrl: './resume-manager.component.html',
  styles: [],
})
export class ResumeManagerComponent {
  private dataService = inject(DataService);
  private ns = inject(NotificationService);

  @Output() close = new EventEmitter<void>();

  resumeHistory = this.dataService.getResumeHistory();

  formatDate(timestamp: number): string {
    return new Date(timestamp).toLocaleString();
  }

  async loadResume(id: string): Promise<void> {
    const ok = await this.ns.confirm(
      'Loading this resume will replace your current view. Your current work will be auto-saved first.',
      'Load Resume',
    );
    if (ok) {
      this.dataService.loadSavedResume(id);
      this.close.emit();
    }
  }

  async deleteResume(id: string, name: string): Promise<void> {
    const ok = await this.ns.confirm(
      `Delete "${name}"? This cannot be undone.`,
      'Delete',
    );
    if (ok) this.dataService.deleteSavedResume(id);
  }

  closeManager(): void {
    this.close.emit();
  }
}
