import {
  Component,
  Input,
  Output,
  EventEmitter,
  inject,
  signal,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Project, SectionType } from '../../models';
import { DataService } from '../../data.service';

@Component({
  selector: 'app-projects-editor',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './projects-editor.html',
})
export class ProjectsEditorComponent {
  private dataService = inject(DataService);
  @Input() projects!: Project[];
  @Output() dataChange = new EventEmitter<void>();

  // Section renaming
  sectionType = SectionType.PROJECTS;
  editingLabel = signal(false);
  labelDraft = '';

  getSectionLabel(): string {
    return this.dataService.getSectionLabel(this.sectionType);
  }
  startRename() {
    this.labelDraft = this.getSectionLabel();
    this.editingLabel.set(true);
  }
  commitRename() {
    this.dataService.setSectionLabel(this.sectionType, this.labelDraft);
    this.editingLabel.set(false);
  }

  getWordCount(text: string): number {
    if (!text) return 0;
    return text
      .trim()
      .split(/\s+/)
      .filter((w) => w.length > 0).length;
  }

  trackByIndex(index: number, item?: any): number {
    return index;
  }

  genId(): string {
    return crypto.randomUUID();
  }

  isActive(id: string): boolean {
    return this.dataService.isActive(id);
  }

  toggleActive(id: string): void {
    this.dataService.toggleActive(id);
  }

  moveSectionItem(arr: any[], index: number, direction: -1 | 1): void {
    const target = index + direction;
    if (target < 0 || target >= arr.length) return;
    [arr[index], arr[target]] = [arr[target], arr[index]];
    this.triggerChange();
  }

  onAddProject() {
    this.projects.push({
      id: this.genId(),
      project_name: '',
      project_url: '',
      project_tech: [''],
      start_date: '',
      end_date: '',
      project_description: [],
    });
    this.triggerChange();
  }

  removeSection(index: number) {
    this.projects.splice(index, 1);
    this.triggerChange();
  }

  onAddProjectDescription(project: Project) {
    if (!project.project_description) project.project_description = [];
    project.project_description.push({ id: this.genId(), text: '' });
    this.triggerChange();
  }

  onRemoveProjectDescription(project: Project, index: number) {
    if (!project.project_description) return;
    project.project_description.splice(index, 1);
    this.triggerChange();
  }

  onAddProjectTech(project: Project) {
    if (!project.project_tech) project.project_tech = [];
    project.project_tech.push('');
    this.triggerChange();
  }

  onRemoveProjectTech(project: Project, index: number) {
    if (!project.project_tech) return;
    project.project_tech.splice(index, 1);
    this.triggerChange();
  }

  private focusTimeouts: { [key: string]: any } = {};

  updateWithoutLosingFocus(fieldId: string) {
    if (this.focusTimeouts[fieldId]) {
      clearTimeout(this.focusTimeouts[fieldId]);
    }
    this.focusTimeouts[fieldId] = setTimeout(() => {
      this.triggerChange();
      this.focusTimeouts[fieldId] = null;
    }, 1500);
  }

  triggerChange() {
    this.dataChange.emit();
  }
}
