import {
  Component,
  Input,
  Output,
  EventEmitter,
  inject,
  signal,
} from '@angular/core';

import { FormsModule } from '@angular/forms';
import { Skill, SectionType } from '../../models';
import { DataService } from '../../data.service';

@Component({
  selector: 'app-skills-editor',
  standalone: true,
  imports: [FormsModule],
  templateUrl: './skills-editor.html',
})
export class SkillsEditorComponent {
  private dataService = inject(DataService);
  @Input() skills!: Skill[];
  @Output() dataChange = new EventEmitter<void>();

  // Section renaming
  sectionType = SectionType.SKILLS;
  editingLabel = signal(false);
  labelDraft = '';

  getSectionLabel(): string {
    return this.dataService.getSectionLabel(this.sectionType);
  }
  startRename() {
    this.labelDraft = this.getSectionLabel();
    this.editingLabel.set(true);
  }
  commitRename() {
    this.dataService.setSectionLabel(this.sectionType, this.labelDraft);
    this.editingLabel.set(false);
  }

  trackByIndex(index: number, item?: any): number {
    return index;
  }

  genId(): string {
    return crypto.randomUUID();
  }

  isActive(id: string): boolean {
    return this.dataService.isActive(id);
  }

  toggleActive(id: string): void {
    this.dataService.toggleActive(id);
  }

  onAddSkillSection() {
    this.skills.push({ id: this.genId(), skill_type: '', skills: [] });
    this.triggerChange();
  }

  addSkillItem(skill: Skill) {
    if (!skill.skills) skill.skills = [];
    skill.skills.push({ id: this.genId(), text: '' });
    this.triggerChange();
  }

  removeSkillItem(skill: Skill, index: number) {
    if (!skill.skills) return;
    skill.skills.splice(index, 1);
    this.triggerChange();
  }

  removeSection(index: number) {
    this.skills.splice(index, 1);
    this.triggerChange();
  }

  onSkillPaste(skill: Skill, index: number, event: ClipboardEvent) {
    const text = event.clipboardData?.getData('text');
    if (!text) return;

    if (text.includes('\n') || text.includes(',')) {
      event.preventDefault();
      const items = text
        .split(/[\n,]+/)
        .map((s) => s.trim())
        .filter((s) => s);
      if (items.length > 0) {
        if (!skill.skills) skill.skills = [];
        skill.skills[index].text = items[0];
        for (let i = 1; i < items.length; i++) {
          skill.skills.splice(index + i, 0, {
            id: this.genId(),
            text: items[i],
          });
        }
        this.triggerChange();
      }
    }
  }

  private focusTimeouts: { [key: string]: any } = {};

  updateWithoutLosingFocus(fieldId: string) {
    if (this.focusTimeouts[fieldId]) {
      clearTimeout(this.focusTimeouts[fieldId]);
    }
    this.focusTimeouts[fieldId] = setTimeout(() => {
      this.triggerChange();
      this.focusTimeouts[fieldId] = null;
    }, 1500);
  }

  triggerChange() {
    this.dataChange.emit();
  }
}
