import { Injectable, inject, computed } from '@angular/core';
import { DataService } from '../data.service';
import { SectionType, Skill, Experience, Project } from '../models';

export interface CompletenessItem {
  label: string;
  passed: boolean;
  points: number;
  tip: string;
  section?: string; // which editor section to navigate to
}

export interface CompletenessResult {
  score: number;
  maxScore: number;
  percent: number;
  items: CompletenessItem[];
}

@Injectable({ providedIn: 'root' })
export class CompletenessService {
  private dataService = inject(DataService);

  /** Reactive completeness result — auto-recalculates on any resume change */
  public result = computed<CompletenessResult>(() => {
    const resume = this.dataService.getResume()();
    const items: CompletenessItem[] = [];

    const personalSection = resume.sections.find(
      (s) => s.type === SectionType.PERSONAL_INFO,
    );
    const info = personalSection?.content as any;

    // Personal info checks
    items.push({
      label: 'Full name, email & phone',
      passed: !!(
        info?.name?.trim() &&
        info?.email?.trim() &&
        info?.phone?.trim()
      ),
      points: 10,
      tip: 'Complete your contact info in Personal Info.',
      section: 'personal-info',
    });
    items.push({
      label: 'At least 1 social or portfolio link',
      passed:
        Array.isArray(info?.links) &&
        info.links.some((l: any) => l.url?.trim()),
      points: 5,
      tip: 'Add a LinkedIn, GitHub, or portfolio link in Personal Info.',
      section: 'personal-info',
    });

    // Summary
    const summaryText = this.dataService.getSummaryText();
    items.push({
      label: 'Professional summary written',
      passed: summaryText.trim().length > 20,
      points: 15,
      tip: "Add a professional summary — it's the first thing recruiters read.",
      section: 'summary',
    });

    // Skills
    const skillSections = resume.sections.filter(
      (s) => s.type === SectionType.SKILLS,
    );
    const hasEnoughSkills =
      skillSections.length >= 2 &&
      skillSections.every(
        (s) => ((s.content as Skill).skills?.length ?? 0) >= 3,
      );
    items.push({
      label: '≥ 2 skill categories with ≥ 3 skills each',
      passed: hasEnoughSkills,
      points: 10,
      tip: 'Add more skill categories. ATS systems weight breadth as well as depth.',
      section: 'skills',
    });

    // Experience
    const experienceSections = resume.sections.filter(
      (s) => s.type === SectionType.EXPERIENCE,
    );
    const activeExps = experienceSections.filter((s) =>
      this.dataService.isActive((s.content as Experience).id),
    );
    items.push({
      label: 'At least 1 active work experience',
      passed: activeExps.length > 0,
      points: 10,
      tip: 'Enable at least one work experience for the current job profile.',
      section: 'experience',
    });

    const allHaveBullets = activeExps.every(
      (s) =>
        ((s.content as Experience).descriptions?.filter(
          (d) => this.dataService.isActive(d.id) && d.text?.trim(),
        ).length ?? 0) >= 2,
    );
    items.push({
      label: 'Each experience has ≥ 2 active bullets',
      passed: allHaveBullets && activeExps.length > 0,
      points: 10,
      tip: 'Add at least 2 bullet points per work experience.',
      section: 'experience',
    });

    // Metrics in bullets
    const metricRegex = /\d+[%×x]?|\$[\d,]+|[0-9]+[kKmM]\b/;
    const anyBulletHasMetric = activeExps.some((s) =>
      (s.content as Experience).descriptions?.some((d) =>
        metricRegex.test(d.text ?? ''),
      ),
    );
    items.push({
      label: 'At least one bullet contains a metric or number',
      passed: anyBulletHasMetric,
      points: 10,
      tip: 'Quantify your impact. e.g. "Reduced load time by 40%" or "Served 10k+ users".',
      section: 'experience',
    });

    // Projects
    const projectSections = resume.sections.filter(
      (s) => s.type === SectionType.PROJECTS,
    );
    const activeProjects = projectSections.filter((s) =>
      this.dataService.isActive((s.content as Project).id),
    );
    items.push({
      label: 'At least 1 active project',
      passed: activeProjects.length > 0,
      points: 10,
      tip: 'Projects are highly valued for engineers, designers, and product managers.',
      section: 'projects',
    });

    // Education
    const hasEducation = resume.sections.some(
      (s) => s.type === SectionType.EDUCATION,
    );
    items.push({
      label: 'Education section present',
      passed: hasEducation,
      points: 5,
      tip: 'Add your education history.',
      section: 'education',
    });

    // Bullet quality
    const noStubBullets = activeExps.every(
      (s) =>
        (s.content as Experience).descriptions
          ?.filter((d) => this.dataService.isActive(d.id))
          .every((d) => d.text?.trim().split(/\s+/).length >= 8) ?? true,
    );
    items.push({
      label: 'All active bullets are ≥ 8 words',
      passed: noStubBullets && activeExps.length > 0,
      points: 5,
      tip: 'Expand stub bullets — short bullets look incomplete and confuse ATS parsers.',
      section: 'experience',
    });

    const totalPoints = items.reduce((sum, i) => sum + i.points, 0);
    const earned = items
      .filter((i) => i.passed)
      .reduce((sum, i) => sum + i.points, 0);

    return {
      score: earned,
      maxScore: totalPoints,
      percent: Math.round((earned / totalPoints) * 100),
      items,
    };
  });
}
