import { Injectable, signal, computed, inject, OnDestroy } from '@angular/core';
import { BusyTexRunner, PdfLatex } from 'texlyre-busytex';
import { DataService } from '../data.service';
import {
  Resume,
  SectionType,
  PersonalInfo,
  Experience,
  Project,
  Education,
  Skill,
  Achievement,
  Summary,
} from '../models/core.models';

// ── Storage keys ─────────────────────────────────────────────────────────────
const KEY_CACHE_MODE = 'rb_latex_cache_mode';  // 'local' | 'cdn'
const KEY_SETUP_DONE = 'rb_latex_setup_done';  // 'true'

// ── Public types ──────────────────────────────────────────────────────────────
export type LatexCacheMode = 'local' | 'cdn';
export type EngineState    = 'idle' | 'initializing' | 'ready' | 'compiling' | 'error';

export interface ProgressState {
  phase: 'initializing' | 'compiling';
  label: string;
  percent: number;
}

@Injectable({ providedIn: 'root' })
export class LatexService implements OnDestroy {
  private ds = inject(DataService);

  // ── Reactive state ────────────────────────────────────────────────────────
  readonly engineState = signal<EngineState>('idle');
  readonly progress    = signal<ProgressState | null>(null);
  readonly lastError   = signal<string | null>(null);
  readonly isBusy      = computed(
    () => this.engineState() === 'initializing' || this.engineState() === 'compiling',
  );

  // ── Preferences ───────────────────────────────────────────────────────────
  readonly cacheMode   = signal<LatexCacheMode>(
    (localStorage.getItem(KEY_CACHE_MODE) as LatexCacheMode) ?? 'local',
  );
  readonly isSetupDone = signal<boolean>(localStorage.getItem(KEY_SETUP_DONE) === 'true');

  // ── Internal ──────────────────────────────────────────────────────────────
  private runner: BusyTexRunner | null = null;
  private prewarmTimer: ReturnType<typeof setTimeout> | null = null;

  // ─────────────────────────────────────────────────────────────────────────
  // Public API
  // ─────────────────────────────────────────────────────────────────────────

  /** Schedule a silent 30s pre-warm if the user has already set up */
  schedulePrewarm(): void {
    if (!this.isSetupDone() || this.runner) return;
    this.prewarmTimer = setTimeout(() => this.initEngine(), 30_000);
  }

  /** Persist user's cache preference and start engine */
  savePreferences(cacheModeVal: LatexCacheMode): void {
    this.cacheMode.set(cacheModeVal);
    localStorage.setItem(KEY_CACHE_MODE, cacheModeVal);
    localStorage.setItem(KEY_SETUP_DONE, 'true');
    this.isSetupDone.set(true);
    this.initEngine();
  }

  /** Reset all preferences – next Download PDF click shows setup again */
  resetPreferences(): void {
    [KEY_CACHE_MODE, KEY_SETUP_DONE].forEach(k => localStorage.removeItem(k));
    this.isSetupDone.set(false);
    this.destroyRunner();
  }

  /** Main entry point called by the Download PDF button */
  async downloadPdf(resume: Resume, activeIds: string[]): Promise<void> {
    this.lastError.set(null);

    if (this.engineState() === 'idle' || this.engineState() === 'error') {
      await this.initEngine();
    }
    if (this.engineState() === 'initializing') {
      await this.waitForReady();
    }
    if (this.engineState() === 'error') {
      throw new Error(this.lastError() ?? 'Engine failed to start.');
    }

    const tex = this.buildTexDocument(resume, activeIds);
    this.engineState.set('compiling');
    this.progress.set({ phase: 'compiling', label: 'Compiling your resume…', percent: 90 });

    try {
      const engine = new PdfLatex(this.runner!);
      const result = await engine.compile({ input: tex });

      if (result.success && result.pdf) {
        this.triggerDownload(result.pdf, this.fileName(resume));
      } else {
        const log = result.log ?? result.logs?.join('\n') ?? 'No log output.';
        throw new Error(`LaTeX compilation failed.\n\nLog:\n${log}`);
      }
    } finally {
      this.engineState.set('ready');
      this.progress.set(null);
    }
  }

  ngOnDestroy(): void {
    if (this.prewarmTimer) clearTimeout(this.prewarmTimer);
    this.destroyRunner();
  }

  // ─────────────────────────────────────────────────────────────────────────
  // Engine lifecycle (private)
  // ─────────────────────────────────────────────────────────────────────────

  private async initEngine(): Promise<void> {
    if (this.runner && this.engineState() === 'ready') return;

    this.engineState.set('initializing');
    this.progress.set({ phase: 'initializing', label: 'Starting PDF engine…', percent: 15 });

    try {
      // Derive asset base path that respects Angular's base href.
      // All busytex assets (worker, wasm, data packages) are served from
      // the same GitHub Pages origin — no CORS issues.
      const base = document.baseURI.endsWith('/') ? document.baseURI : document.baseURI + '/';
      const busytexBasePath = `${base}core/busytex`;
      const texliveBasicJs = `${busytexBasePath}/texlive-basic.js`;

      this.progress.set({ phase: 'initializing', label: 'Loading TeX engine…', percent: 40 });

      this.runner = new BusyTexRunner({
        busytexBasePath,
        preloadDataPackages: [texliveBasicJs],
        catalogDataPackages: [texliveBasicJs],
      });
      await this.runner.initialize();

      this.engineState.set('ready');
      this.progress.set(null);
    } catch (err: any) {
      const msg = err?.message ?? String(err);
      this.engineState.set('error');
      this.lastError.set(msg);
      this.progress.set(null);
      throw err;
    }
  }

  private waitForReady(): Promise<void> {
    return new Promise(resolve => {
      const check = () => {
        const s = this.engineState();
        if (s === 'ready' || s === 'error') { resolve(); return; }
        setTimeout(check, 200);
      };
      check();
    });
  }

  private destroyRunner(): void {
    this.runner = null;
    this.engineState.set('idle');
  }

  // ─────────────────────────────────────────────────────────────────────────
  // Download trigger
  // ─────────────────────────────────────────────────────────────────────────

  private triggerDownload(pdf: Uint8Array | ArrayBuffer, filename: string): void {
    const buffer = pdf instanceof Uint8Array ? pdf.buffer as ArrayBuffer : pdf;
    const blob   = new Blob([buffer], { type: 'application/pdf' });
    const url    = URL.createObjectURL(blob);
    const a      = document.createElement('a');
    a.href       = url;
    a.download   = filename;
    document.body.appendChild(a);
    a.click();
    URL.revokeObjectURL(url);
    document.body.removeChild(a);
  }

  private fileName(resume: Resume): string {
    const pi   = resume.sections.find(s => s.type === SectionType.PERSONAL_INFO)?.content as PersonalInfo | undefined;
    const name = pi?.name?.trim().replace(/\s+/g, '_') ?? 'resume';
    return `${name}_resume.pdf`;
  }

  // ─────────────────────────────────────────────────────────────────────────
  // .tex document builder
  // ─────────────────────────────────────────────────────────────────────────

  buildTexDocument(resume: Resume, activeIds: string[]): string {
    const active   = new Set(activeIds);
    const isActive = (id: string) => active.size === 0 || active.has(id);
    const e        = (t: string | number | undefined | null) => this.escape(String(t ?? ''));

    // Read page margins from DataService (mm) → convert to inches for geometry
    const marginV = this.ds.getPageMarginV()() ?? 15;
    const marginH = this.ds.getPageMarginH()() ?? 20;
    const toIn    = (mm: number) => (Math.max(8, mm) / 25.4).toFixed(2) + 'in';
    const top = toIn(marginV), bottom = toIn(marginV);
    const left = toIn(marginH), right = toIn(marginH);

    const pi           = resume.sections.find(s => s.type === SectionType.PERSONAL_INFO)?.content as PersonalInfo | undefined;
    const summaryRaw   = resume.sections.find(s => s.type === SectionType.SUMMARY)?.content as Summary | undefined;
    const experiences  = resume.sections.filter(s => s.type === SectionType.EXPERIENCE).map(s => s.content as Experience).filter(ex => isActive(ex.id));
    const projects     = resume.sections.filter(s => s.type === SectionType.PROJECTS).map(s => s.content as Project).filter(p => isActive(p.id));
    const educations   = resume.sections.filter(s => s.type === SectionType.EDUCATION).map(s => s.content as Education).filter(ed => isActive(ed.id));
    const skills       = resume.sections.filter(s => s.type === SectionType.SKILLS).map(s => s.content as Skill).filter(sk => isActive(sk.id));
    const achievements = resume.sections.filter(s => s.type === SectionType.ACHIEVEMENT).map(s => s.content as Achievement).filter(a => isActive(a.id));

    const eu       = (url: string) => this.escapeUrl(url);

    const links = (pi?.links ?? [])
      .filter(l => l.url?.trim())
      .map(l => `\\href{${eu(l.url)}}{${e(l.preview_name)}}`)
      .join(' {\\textbar} ');

    const contactParts = [
      pi?.email ? `\\href{mailto:${eu(pi.email)}}{${e(pi.email)}}` : '',
      pi?.phone ? `\\href{tel:${eu(pi.phone)}}{${e(pi.phone)}}` : '',
      links,
    ].filter(Boolean).join(' \\,|\\, ');

    const sectionOrder = resume.sections
      .map(s => s.type)
      .filter((t, i, arr) => arr.indexOf(t) === i && t !== SectionType.PERSONAL_INFO);

    let body = '';
    for (const sType of sectionOrder) {
      switch (sType) {
        case SectionType.SUMMARY: {
          if (summaryRaw?.text?.trim()) {
            body += `\\resumesection{${e(this.ds.getSectionLabel(SectionType.SUMMARY))}}\n${e(summaryRaw.text)}\n\\par\\entryspace\n`;
          }
          break;
        }
        case SectionType.EXPERIENCE: {
          if (!experiences.length) break;
          body += `\\resumesection{${e(this.ds.getSectionLabel(SectionType.EXPERIENCE))}}\n`;
          for (const exp of experiences) {
            const bullets = exp.descriptions.filter(b => isActive(b.id) && b.text?.trim());
            const company = [e(exp.company), exp.location ? e(exp.location) : ''].filter(Boolean).join(', ');
            const dates   = [e(exp.start_date), e(exp.end_date)].filter(Boolean).join(' \\textendash{} ');
            body += `\\resumeEntry{${e(exp.position)}}{${company}}{${dates}}\n`;
            if (bullets.length) body += this.bulletList(bullets, e);
            body += `\\par\\entryspace\n`;
          }
          break;
        }
        case SectionType.PROJECTS: {
          if (!projects.length) break;
          body += `\\resumesection{${e(this.ds.getSectionLabel(SectionType.PROJECTS))}}\n`;
          for (const p of projects) {
            const tech    = p.project_tech.filter(Boolean).map(t => e(t)).join(', ');
            const bullets = p.project_description.filter(b => isActive(b.id) && b.text?.trim());
            const dates   = [e(p.start_date), e(p.end_date)].filter(Boolean).join(' \\textendash{} ');
            const nameStr = p.project_url?.trim()
              ? `\\href{${eu(p.project_url)}}{${e(p.project_name)}}`
              : e(p.project_name);
            body += `\\resumeEntry{${nameStr}}{${tech}}{${dates}}\n`;
            if (bullets.length) body += this.bulletList(bullets, e);
            body += `\\par\\entryspace\n`;
          }
          break;
        }
        case SectionType.EDUCATION: {
          if (!educations.length) break;
          body += `\\resumesection{${e(this.ds.getSectionLabel(SectionType.EDUCATION))}}\n`;
          for (const ed of educations) {
            const school = [e(ed.school), ed.location ? e(ed.location) : ''].filter(Boolean).join(', ');
            const gpa    = ed.gpa ? ` \\textendash{} ${e(ed.gpa)} CGPA` : '';
            const dates  = [e(ed.start_date), e(ed.end_date)].filter(Boolean).join(' \\textendash{} ');
            body += `\\resumeEntry{${school}}{${e(ed.degree)}${gpa}}{${dates}}\n\\par\\entryspace\n`;
          }
          break;
        }
        case SectionType.SKILLS: {
          if (!skills.length) break;
          body += `\\resumesection{${e(this.ds.getSectionLabel(SectionType.SKILLS))}}\n\\begin{skillslist}\n`;
          for (const sk of skills) {
            const items = sk.skills.filter(s => isActive(s.id) && s.text?.trim()).map(s => e(s.text)).join(', ');
            if (items) body += `  \\item[\\textbf{${e(sk.skill_type)}:}] ${items}\n`;
          }
          body += `\\end{skillslist}\n`;
          break;
        }
        case SectionType.ACHIEVEMENT: {
          if (!achievements.length) break;
          body += `\\resumesection{${e(this.ds.getSectionLabel(SectionType.ACHIEVEMENT))}}\n`;
          for (const ach of achievements) {
            const bullets = ach.description.filter(b => isActive(b.id) && b.text?.trim());
            body += `\\noindent\\textbf{${e(ach.title)}}\\par\\vspace{2pt}\n`;
            if (bullets.length) body += this.bulletList(bullets, e);
            else body += `\\par\n`;
            body += `\\par\\entryspace\n`;
          }
          break;
        }
      }
    }

    // ── LaTeX document ───────────────────────────────────────────────────────
    // Uses only texlive-basic packages: geometry, fontenc, inputenc, lmodern,
    // hyperref, tabularx. All spacing done with primitives.
    // Guard: if name is missing, skip the name line entirely (avoid blank \\[4pt])
    const nameBlock = pi?.name?.trim()
      ? `  {\\Huge\\bfseries ${e(pi.name)}}\\\\[4pt]\n  {\\small ${contactParts}}`
      : `  {\\small ${contactParts}}`;

    return [
      `\\documentclass[10pt,letterpaper]{article}`,
      ``,
      `\\usepackage[top=${top},bottom=${bottom},left=${left},right=${right}]{geometry}`,
      `\\usepackage[T1]{fontenc}`,
      `\\usepackage[utf8]{inputenc}`,
      `\\usepackage{lmodern}`,

      `\\usepackage[hidelinks,pdfusetitle]{hyperref}`,
      `\\usepackage{tabularx}`,
      ``,
      `\\hypersetup{%`,
      `  pdfauthor={${e(pi?.name ?? '')}},%`,
      `  pdftitle={${e(pi?.name ?? '')} Resume},%`,
      `  pdfsubject={Resume},%`,
      `  pdfcreator={Resume Builder}%`,
      `}`,
      ``,
      `\\pagestyle{empty}`,
      `\\setlength{\\parindent}{0pt}`,
      `\\setlength{\\parskip}{0pt}`,
      `\\setlength{\\tabcolsep}{0pt}`,
      ``,
      `% --- Section heading ---`,
      `% Bold large title, 0.5pt rule below, consistent spacing above/below`,
      `\\newcommand{\\resumesection}[1]{%`,
      `  \\vspace{8pt}%`,
      `  {\\large\\bfseries #1}\\\\[-6pt]%`,
      `  \\rule{\\textwidth}{0.4pt}%`,
      `  \\vspace{2pt}%`,
      `  \\par\\noindent`,
      `}`,
      ``,
      `% --- Entry spacing between entries within a section ---`,
      `\\newcommand{\\entryspace}{\\vspace{4pt}}`,
      ``,
      `% --- Job/project/education entry ---`,
      `% Row 1: bold title (left) + small date (right)`,
      `% Row 2: italic subtitle (left)`,
      `\\newcommand{\\resumeEntry}[3]{%`,
      `  \\begin{tabularx}{\\textwidth}{@{}X r@{}}`,
      `    \\textbf{#1} & {\\small\\normalfont #3} \\\\`,
      `    {\\small\\itshape #2} & \\\\`,
      `  \\end{tabularx}%`,
      `  \\vspace{3pt}%`,
      `}`,
      ``,
      `% --- Compact bullet list (for experience / project / achievement bullets) ---`,
      `\\newenvironment{resumelist}{%`,
      `  \\begin{list}{\\textbullet}{%`,
      `    \\setlength{\\topsep}{1pt}%`,
      `    \\setlength{\\partopsep}{0pt}%`,
      `    \\setlength{\\itemsep}{1pt}%`,
      `    \\setlength{\\parsep}{0pt}%`,
      `    \\setlength{\\parskip}{0pt}%`,
      `    \\setlength{\\leftmargin}{1.3em}%`,
      `    \\setlength{\\labelsep}{0.4em}%`,
      `  }%`,
      `}{\\end{list}}`,
      ``,
      `% --- Label-style list for Skills (no bullet, category name as label) ---`,
      `\\newenvironment{skillslist}{%`,
      `  \\begin{list}{}{%`,
      `    \\setlength{\\topsep}{1pt}%`,
      `    \\setlength{\\partopsep}{0pt}%`,
      `    \\setlength{\\itemsep}{2pt}%`,
      `    \\setlength{\\parsep}{0pt}%`,
      `    \\setlength{\\parskip}{0pt}%`,
      `    \\setlength{\\leftmargin}{0pt}%`,
      `    \\setlength{\\labelwidth}{0pt}%`,
      `    \\setlength{\\labelsep}{0pt}%`,
      `  }%`,
      `}{\\end{list}}`,
      ``,
      `\\begin{document}`,
      ``,
      `\\begin{center}`,
      nameBlock,
      `\\end{center}`,
      `\\vspace{4pt}`,
      ``,
      body,
      `\\end{document}`,
    ].join('\n');
  }

  private bulletList(bullets: { text: string }[], e: (s: any) => string): string {
    let out = `\\begin{resumelist}\n`;
    for (const b of bullets) out += `  \\item ${e(b.text)}\n`;
    out += `\\end{resumelist}\n`;
    return out;
  }

  private escape(text: string): string {
    return text
      .replace(/\r?\n/g, ' ')              // collapse newlines to spaces
      .replace(/\\/g,  '\\textbackslash{}')
      .replace(/&/g,   '\\&')
      .replace(/%/g,   '\\%')
      .replace(/\$/g,  '\\$')
      .replace(/#/g,   '\\#')
      .replace(/_/g,   '\\_')
      .replace(/\{/g,  '\\{')
      .replace(/\}/g,  '\\}')
      .replace(/~/g,   '\\textasciitilde{}')
      .replace(/\^/g,  '\\textasciicircum{}');
  }

  /**
   * Escape a URL for use inside \href{URL}{...}.
   * hyperref handles most URL characters natively — only % and # conflict
   * with LaTeX's own syntax and need escaping. Characters like _ ~ & are
   * valid URL characters and must NOT be escaped here.
   */
  private escapeUrl(url: string): string {
    return url
      .replace(/%/g, '\\%')
      .replace(/#/g, '\\#');
  }
}
