import {
  Component,
  inject,
  HostListener,
  OnDestroy,
  signal,
  ViewChild,
  ElementRef,
} from '@angular/core';

import { DomSanitizer, SafeHtml } from '@angular/platform-browser';

import { FormsModule } from '@angular/forms';
import { RouterLink } from '@angular/router';
import { DataService } from '../data.service';
import { ResumeManagerComponent } from '../resume-manager/resume-manager.component';
import { ProfileManagerComponent } from '../profile-manager/profile-manager.component';
import { NotificationService } from '../services/notification.service';
import { ExperienceTier, EXPERIENCE_TIERS } from '../models/llm.models';
import { CompletenessService } from '../services/completeness.service';
import { ThemeService } from '../services/theme.service';

@Component({
  selector: 'app-resume-controls',
  standalone: true,
  imports: [
    FormsModule,
    ResumeManagerComponent,
    RouterLink,
    ProfileManagerComponent,
  ],
  templateUrl: './resume-controls.components.html',
  styles: [
    `
      .resume-controls {
        font-family: 'Inter', sans-serif;
      }
    `,
  ],
})
export class ResumeControlsComponent implements OnDestroy {
  private dataService = inject(DataService);
  private ns = inject(NotificationService);
  public completeness = inject(CompletenessService);
  public themeService = inject(ThemeService);
  private sanitizer = inject(DomSanitizer);

  @ViewChild('jsonHighlightLayer')
  jsonHighlightLayer!: ElementRef<HTMLPreElement>;

  // Tier
  tiers = EXPERIENCE_TIERS;
  currentTier = this.dataService.getCurrentTierSignal();
  changeTier(value: ExperienceTier) {
    this.dataService.setCurrentTier(value);
  }

  syncJsonScroll(event: Event) {
    if (this.jsonHighlightLayer) {
      const textarea = event.target as HTMLTextAreaElement;
      this.jsonHighlightLayer.nativeElement.scrollTop = textarea.scrollTop;
      this.jsonHighlightLayer.nativeElement.scrollLeft = textarea.scrollLeft;
    }
  }

  highlightedJson(): SafeHtml {
    let text = this.importJSON;
    if (!text) return this.sanitizer.bypassSecurityTrustHtml('');

    // Escape HTML first
    text = text
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;');

    // Robust JSON regex highlighter
    const jsonRegex =
      /("(\\u[a-zA-Z0-9]{4}|\\[^u]|[^\\"])*"(\s*:)?|\b(true|false|null)\b|-?\d+(?:\.\d*)?(?:[eE][+-]?\d+)?)/g;

    text = text.replace(jsonRegex, (match) => {
      let cls = 'text-amber-600 dark:text-amber-400'; // number
      if (/^"/.test(match)) {
        if (/:$/.test(match)) {
          cls = 'text-sky-600 dark:text-sky-400 font-semibold'; // key
          const keyStr = match.substring(0, match.lastIndexOf('"') + 1);
          const colonStr = match.substring(match.lastIndexOf('"') + 1);
          return `<span class="${cls}">${keyStr}</span>${colonStr}`;
        } else {
          cls = 'text-green-600 dark:text-green-400'; // string value
        }
      } else if (/true|false/.test(match)) {
        cls = 'text-fuchsia-600 dark:text-fuchsia-400 font-bold'; // boolean
      } else if (/null/.test(match)) {
        cls = 'text-fuchsia-600 dark:text-fuchsia-400 font-bold'; // null
      }
      return `<span class="${cls}">${match}</span>`;
    });

    return this.sanitizer.bypassSecurityTrustHtml(text);
  }

  // Template data
  availableTemplates = this.dataService.getAvailableTemplates();
  history = this.dataService.getResumeHistory();

  // Undo/Redo State
  canUndo = this.dataService.canUndo;
  canRedo = this.dataService.canRedo;

  undo() {
    this.dataService.undo();
  }
  redo() {
    this.dataService.redo();
  }

  // Auto-save status — tick every 10s to keep label fresh
  private lastSavedAt = signal<number>(Date.now());
  private _tick = signal<number>(0);
  private tickInterval = setInterval(
    () => this._tick.update((n) => n + 1),
    10_000,
  );

  lastSavedLabel(): string {
    this._tick(); // subscribe to tick so this recomputes every 10s
    const sec = Math.floor((Date.now() - this.lastSavedAt()) / 1000);
    if (sec < 5) return 'Just saved';
    if (sec < 60) return `Saved ${sec}s ago`;
    return `Saved ${Math.floor(sec / 60)}m ago`;
  }

  private markSaved() {
    this.lastSavedAt.set(Date.now());
    this._tick.update((n) => n + 1);
  }

  ngOnDestroy() {
    clearInterval(this.tickInterval);
  }

  // UI state
  showSaveDialog = false;
  showCompleteness = false;
  showImportDialog = false;
  showResumeManager = false;
  resumeName = '';
  importJSON = '';
  savedToast = false;
  private toastTimer: ReturnType<typeof setTimeout> | null = null;

  @HostListener('document:keydown', ['$event'])
  handleKeydown(e: KeyboardEvent) {
    const mod = e.ctrlKey || e.metaKey;
    if (mod && e.key === 's') {
      e.preventDefault();
      this.quickSave();
    } else if (mod && e.key === 'z' && !e.shiftKey) {
      e.preventDefault();
      this.undo();
    } else if (mod && (e.key === 'y' || (e.key === 'z' && e.shiftKey))) {
      e.preventDefault();
      this.redo();
    }
  }

  quickSave(): void {
    this.dataService.overwriteCurrentSlot();
    this.markSaved();
    this.savedToast = true;
    if (this.toastTimer) clearTimeout(this.toastTimer);
    this.toastTimer = setTimeout(() => {
      this.savedToast = false;
    }, 2000);
  }

  // Format date for display
  formatDate(timestamp: number): string {
    return new Date(timestamp).toLocaleString();
  }

  // Sample resume loading
  async loadSampleResume(templateId: string): Promise<void> {
    const ok = await this.ns.confirm(
      'Loading a sample resume will replace your current content. This will auto-save your work first.',
      'Load Sample',
    );
    if (ok) this.dataService.loadSampleResume(templateId);
  }

  // Open Save As dialog — pre-fill name from current slot
  openSaveDialog(): void {
    const h = this.history();
    const currentSlot = h.savedResumes.find((r) => r.id === h.currentResumeId);
    this.resumeName = currentSlot?.name ?? '';
    this.showSaveDialog = true;
  }

  // Save current resume
  saveResume(): void {
    if (this.resumeName) {
      const resumeId = this.dataService.saveCurrentResume(this.resumeName);
      if (resumeId) {
        this.showSaveDialog = false;
        this.resumeName = '';
        // Show the resume manager after saving
        setTimeout(() => {
          this.showResumeManager = true;
        }, 300);
      }
    }
  }

  // Load a saved resume
  async loadResume(id: string): Promise<void> {
    const ok = await this.ns.confirm(
      'Loading this resume will replace your current view. Your current work will be auto-saved first.',
      'Load Resume',
    );
    if (ok) this.dataService.loadSavedResume(id);
  }

  // Delete a saved resume
  async deleteResume(id: string, name: string): Promise<void> {
    const ok = await this.ns.confirm(
      `Delete "${name}"? This cannot be undone.`,
      'Delete',
    );
    if (ok) this.dataService.deleteSavedResume(id);
  }

  // Export resume as JSON
  exportResume(): void {
    const jsonData = this.dataService.exportCurrentResumeToJSON();

    // Create a download link
    const blob = new Blob([jsonData], { type: 'application/json' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'resume.json';
    document.body.appendChild(a);
    a.click();
    window.URL.revokeObjectURL(url);
    document.body.removeChild(a);
  }

  // Import resume from JSON
  importResumeFromJSON(): void {
    if (this.importJSON) {
      try {
        const success = this.dataService.importResumeFromJSON(this.importJSON);
        if (success) {
          this.showImportDialog = false;
          this.importJSON = '';
          this.ns.toast(
            'Resume imported successfully! Your previous work was auto-saved.',
            'success',
          );
        } else {
          this.ns.toast(
            'Invalid resume data. Please check your JSON format.',
            'error',
          );
        }
      } catch (error) {
        this.ns.toast('Error importing resume: ' + error, 'error');
      }
    }
  }
}
