import {
  Component,
  inject,
  HostListener,
  ViewChild,
  ElementRef,
  effect,
  signal,
} from '@angular/core';
import { DataService } from '../data.service';
import { NotificationService } from '../services/notification.service';
import { LatexService, LatexCacheMode } from '../services/latex.service';
import {
  Achievement,
  BulletPoint,
  Education,
  Experience,
  PersonalInfo,
  Project,
  SectionType,
  Skill,
} from '../models';

@Component({
  selector: 'app-edit-preview',
  templateUrl: './edit-preview.component.html',
  styleUrls: ['./edit-preview.component.scss'],
  imports: [], // Add JsonPipe to imports
  standalone: true,
})
export class EditPreviewComponent {
  private dataSerice = inject(DataService);
  private ns         = inject(NotificationService);
  public  latex      = inject(LatexService);

  @ViewChild('resumeContent') resumeContent!: ElementRef;

  public isCopied = false;

  public current_resume = this.dataSerice.getResume();
  public current_template = this.dataSerice.getTemplate();
  public current_font = this.dataSerice.getFont();
  public current_font_size = this.dataSerice.getFontSize();
  public page_margin_v = this.dataSerice.getPageMarginV();
  public page_margin_h = this.dataSerice.getPageMarginH();

  // ── LaTeX setup modal state ──────────────────────────────────────────────
  showSetupModal = signal(false);
  modalCacheMode = signal<LatexCacheMode>('local');

  constructor() {
    // Keep CSS custom properties for DevTools print emulation
    effect(() => {
      document.documentElement.style.setProperty(
        '--resume-margin-v',
        this.page_margin_v() + 'mm',
      );
      document.documentElement.style.setProperty(
        '--resume-margin-h',
        this.page_margin_h() + 'mm',
      );
    });
    // Schedule silent engine pre-warm if user has previously set up LaTeX
    this.latex.schedulePrewarm();
  }

  /** Apply user-defined print margins as inline styles — inline styles win over all CSS rules */
  @HostListener('window:beforeprint')
  onBeforePrint(): void {
    const wrapper = document.querySelector(
      '.resume-wrapper',
    ) as HTMLElement | null;
    if (wrapper) {
      wrapper.style.padding = `${this.page_margin_v()}mm ${this.page_margin_h()}mm`;
    }
  }

  /** Restore screen padding after printing */
  @HostListener('window:afterprint')
  onAfterPrint(): void {
    const wrapper = document.querySelector(
      '.resume-wrapper',
    ) as HTMLElement | null;
    if (wrapper) {
      wrapper.style.padding = ''; // falls back to SCSS padding: 40px 48px
    }
  }

  /** Fires the shared signal so EditorComponent opens and scrolls to the settings panel */
  openPrintSettings(): void {
    this.dataSerice.triggerOpenSettings();
  }

  /** Returns true if a value is non-empty and not the 'NO VALUE' placeholder */
  isValue(v: string | undefined | null): boolean {
    return !!v && v.trim().toUpperCase() !== 'NO VALUE' && v.trim() !== '';
  }

  /** Trims leading/trailing whitespace from a display value */
  t(v: string | undefined | null): string {
    return (v ?? '').trim();
  }

  // Expose SectionType enum to template
  public readonly SectionType = SectionType;

  /**
   * Returns unique section types in the order they appear in the resume.
   * @param includeSkills - false for modern template (skills live in sidebar)
   */
  getSectionOrder(includeSkills: boolean): SectionType[] {
    const seen = new Set<SectionType>();
    const order: SectionType[] = [];
    for (const s of this.current_resume().sections) {
      if (s.type === SectionType.PERSONAL_INFO) continue;
      if (!includeSkills && s.type === SectionType.SKILLS) continue;
      if (!seen.has(s.type)) {
        seen.add(s.type);
        order.push(s.type);
      }
    }
    return order;
  }

  /** Browser print dialog — quick share with humans */
  printResume(): void {
    window.print();
  }

  /** Entry point for Download PDF button */
  onDownloadPdfClick(): void {
    if (!this.latex.isSetupDone()) {
      this.modalCacheMode.set('local');
      this.showSetupModal.set(true);
      return;
    }
    this.runLatexDownload();
  }

  /** Confirm button inside setup modal */
  confirmSetup(): void {
    this.showSetupModal.set(false);
    this.latex.savePreferences(this.modalCacheMode());
    this.runLatexDownload();
  }

  /** Re-open setup modal (cache preference change) */
  openSetupModal(): void {
    this.modalCacheMode.set(this.latex.cacheMode());
    this.showSetupModal.set(true);
  }

  private async runLatexDownload(): Promise<void> {
    const resume    = this.dataSerice.getResume()();
    const profile   = this.dataSerice.getActiveProfile();
    const activeIds = profile?.activeIds ?? [];
    try {
      await this.latex.downloadPdf(resume, activeIds);
    } catch (err: any) {
      const msg = err?.message ?? String(err);
      if (msg !== 'Cancelled') {
        this.ns.toast('PDF generation failed: ' + msg, 'error');
      }
    }
  }

  async copyAsPlainText(): Promise<void> {
    const rawContext = this.dataSerice.buildAIContext();
    // buildAIContext returns an XML-ish format like <EXPERIENCE>...</EXPERIENCE>
    // Let's strip the XML tags to make it clean plain text
    const cleanText = rawContext
      .replace(/<[^>]+>/g, '')
      .replace(/\n{3,}/g, '\n\n')
      .trim();

    try {
      await navigator.clipboard.writeText(cleanText);
      this.isCopied = true;
      setTimeout(() => {
        this.isCopied = false;
      }, 2000);
    } catch (err) {
      console.error('Failed to copy resume to clipboard:', err);
    }
  }

  getPersonalInfo(): PersonalInfo | undefined {
    return this.current_resume().sections.find(
      (section) => section.type === SectionType.PERSONAL_INFO,
    )?.content as PersonalInfo | undefined;
  }

  getSummaryText(): string {
    return this.dataSerice.getSummaryText();
  }

  getSkills(): Skill[] {
    return this.current_resume()
      .sections.filter((section) => section.type === SectionType.SKILLS)
      .map((section) => section.content) as Skill[];
  }

  getExperiences(): Experience[] {
    return this.current_resume()
      .sections.filter((section) => section.type === SectionType.EXPERIENCE)
      .map((section) => section.content) as Experience[];
  }

  getProjects(): Project[] {
    return this.current_resume()
      .sections.filter((section) => section.type === SectionType.PROJECTS)
      .map((section) => section.content) as Project[];
  }
  getEducations(): Education[] {
    return this.current_resume()
      .sections.filter((section) => section.type === SectionType.EDUCATION)
      .map((section) => section.content) as Education[];
  }

  getAchievements(): Achievement[] {
    return this.current_resume()
      .sections.filter((section) => section.type === SectionType.ACHIEVEMENT)
      .map((section) => section.content) as Achievement[];
  }

  // ── Profile-aware active filtering ──────────────────────────────────────

  /** Delegate to DataService — used in template to check active state */
  isActive(id: string): boolean {
    return this.dataSerice.isActive(id);
  }

  /** Returns display label for a section type (respects user renames) */
  getSectionLabel(type: SectionType): string {
    return this.dataSerice.getSectionLabel(type);
  }

  /** Entries (experience / project / education / achievement) whose entry-level ID is active */
  getActiveExperiences(): Experience[] {
    return this.getExperiences().filter((e) => this.isActive(e.id));
  }
  getActiveProjects(): Project[] {
    return this.getProjects().filter((p) => this.isActive(p.id));
  }
  getActiveEducations(): Education[] {
    return this.getEducations().filter((e) => this.isActive(e.id));
  }
  getActiveAchievements(): Achievement[] {
    return this.getAchievements().filter((a) => this.isActive(a.id));
  }
  getActiveSkills(): Skill[] {
    return this.getSkills().filter((s) => this.isActive(s.id));
  }

  /** Active bullets within an entry (entry must itself be active) */
  getActiveBullets(bullets: BulletPoint[], entryId: string): BulletPoint[] {
    if (!this.isActive(entryId)) return [];
    return bullets.filter((b) => this.isActive(b.id));
  }

  /** Active individual skill items within a skill category */
  getActiveSkillItems(skill: Skill): BulletPoint[] {
    if (!this.isActive(skill.id)) return [];
    return skill.skills.filter((s) => this.isActive(s.id));
  }
}
