import { Component, HostListener } from '@angular/core';
import { EditorComponent } from '../editor/editor.component';
import { EditPreviewComponent } from '../edit-preview/edit-preview.component';
import { ResumeControlsComponent } from '../resume-controls/resume-controls.component';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-manual-builder',
  standalone: true,
  imports: [
    CommonModule,
    EditorComponent,
    EditPreviewComponent,
    ResumeControlsComponent,
  ],
  templateUrl: './manual-builder.component.html',
  styleUrl: './manual-builder.component.scss',
})
export class ManualBuilderComponent {
  public window_width: number;
  public isDragging = false;
  private minWidth = 320;
  private maxWidth = 0; // set on first drag
  private startX = 0;
  private startWidth = 0;

  constructor() {
    const savedWidth = localStorage.getItem('resume-builder-panel-width');
    this.window_width = savedWidth
      ? parseInt(savedWidth)
      : window.innerWidth * 0.48;
  }

  onDragStart(e: PointerEvent): void {
    e.preventDefault();
    this.isDragging = true;
    this.startX = e.clientX;
    this.startWidth = this.window_width;
    this.maxWidth = window.innerWidth * 0.72;
    (e.target as HTMLElement).setPointerCapture(e.pointerId);
  }

  @HostListener('document:pointermove', ['$event'])
  onDragMove(e: PointerEvent): void {
    if (!this.isDragging) return;
    const delta = e.clientX - this.startX;
    const next = Math.min(
      this.maxWidth,
      Math.max(this.minWidth, this.startWidth + delta),
    );
    this.window_width = next;
  }

  @HostListener('document:pointerup', ['$event'])
  onDragEnd(_e: PointerEvent): void {
    if (!this.isDragging) return;
    this.isDragging = false;
    localStorage.setItem(
      'resume-builder-panel-width',
      this.window_width.toString(),
    );
  }
}
